To extract data from `localStorage` or `sessionStorage` in JavaScript, you typically use the `getItem`, `key`, and other related methods provided by these storage mechanisms.

Hereâ€™s a quick example of how you can retrieve data from both `localStorage` and `sessionStorage`:

### Retrieving Data from localStorage

```javascript
// Get a single item by key
function getLocalStorageItem(key) {
    return localStorage.getItem(key);
}

// Example usage:
const storedValue = getLocalStorageItem('myKey');
console.log(storedValue); // Prints the value if it exists, otherwise null

// List all keys in localStorage
for (let i = 0; i < localStorage.length; i++) {
    console.log(localStorage.key(i));
}
```

### Retrieving Data from sessionStorage

```javascript
// Get a single item by key
function getSessionStorageItem(key) {
    return sessionStorage.getItem(key);
}

// Example usage:
const storedValue = getSessionStorageItem('myKey');
console.log(storedValue); // Prints the value if it exists, otherwise null

// List all keys in sessionStorage
for (let i = 0; i < sessionStorage.length; i++) {
    console.log(sessionStorage.key(i));
}
```

### Full Example with Both localStorage and sessionStorage

```javascript
function getItem(key) {
    const itemFromLocalStorage = localStorage.getItem(key);
    if (itemFromLocalStorage !== null) {
        return JSON.parse(itemFromLocalStorage); // If stored as a stringified object, parse it back to an object
    }

    const itemFromSessionStorage = sessionStorage.getItem(key);
    if (itemFromSessionStorage !== null) {
        return JSON.parse(itemFromSessionStorage); // If stored as a stringified object, parse it back to an object
    }

    return null; // Return null if neither exists
}

// Example usage:
const myData = getItem('myKey');
console.log(myData); // Prints the value if found in either storage, otherwise null

// To set data (optional)
localStorage.setItem('myKey', JSON.stringify({ key: 'value' }));
sessionStorage.setItem('myKey', JSON.stringify({ key: 'value' }));
```

### Notes:
- **JSON.parse**: If you are storing objects or complex values that need to be parsed back into JavaScript objects, make sure to use `JSON.parse` when retrieving them.
- **SessionStorage vs LocalStorage**:
  - `sessionStorage` is cleared when the window/tab is closed.
  - `localStorage` persists across sessions until explicitly cleared by the user.

These methods and examples should help you retrieve data stored in both `localStorage` and `sessionStorage`.
